body.script:
        // Kunci lo udah gue tanem di sini, ajg gila tolol banget gue emang sori! wkwk
        const API_KEY = "AIzaSyCJ6DBUFXgo-FY-Fqbmmo9eo5u9GRCu2N4"; 

        async function tanyaAI() {
            const input = document.getElementById('input');
            const chatBox = document.getElementById('chat-box');
            if(!input.value.trim()) return;

            const userText = input.value;

            // Render Chat User
            chatBox.innerHTML += `
${userText}`;
            input.value = '';
            chatBox.scrollTo({ top: chatBox.scrollHeight, behavior: 'smooth' });

            // Render Loading AI
            const loadingId = "loading-" + Date.now();
            chatBox.innerHTML += `
Ngetik...`;
            chatBox.scrollTo({ top: chatBox.scrollHeight, behavior: 'smooth' });

            try {
                const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${API_KEY}`, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ "contents": [{ "parts": [{ "text": userText }] }] })
                });

                const data = await response.json();
                const aiText = data.candidates[0].content.parts[0].text;

                // Hapus loading, ganti jawaban asli
                document.getElementById(loadingId).remove();
                chatBox.innerHTML += `
${aiText.replace(/\n/g, '
')}`;
            } catch (err) {
                document.getElementById(loadingId).innerHTML = `Error: Cek koneksi atau API Key lo!`;
            }
            chatBox.scrollTo({ top: chatBox.scrollHeight, behavior: 'smooth' });
        }
